import{_ as a,o as i,c,ag as o}from"./chunks/framework.DTiDeF2Q.js";const p=JSON.parse('{"title":"Bí Danh Archives | Dotfiles (VI)","titleTemplate":":title","description":"Tên lệnh nén rút gọn. Tổng quan cho Dotfiles v0.2.495. Tương thích với macOS, Linux và WSL qua Dotfiles.","frontmatter":{"title":"Bí Danh Archives | Dotfiles","description":"Tên lệnh nén rút gọn. Tổng quan cho Dotfiles v0.2.495. Tương thích với macOS, Linux và WSL qua Dotfiles.","lang":"vi-VN","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Bí Danh Archives | Dotfiles preview","canonical":"/vi/aliases/archives/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Bí danh Archives","pageType":"docs","schemaType":"WebPage","permalink":"/vi/aliases/archives/"},"headers":[],"relativePath":"vi/aliases/archives/index.md","filePath":"vi/aliases/archives/index.md","lastUpdated":1773010926000}'),n={name:"vi/aliases/archives/index.md"};function t(h,e,l,d,r,s){return i(),c("div",null,[...e[0]||(e[0]=[o('<h1 id="bi-danh-archives" tabindex="-1">Bí Danh Archives <a class="header-anchor" href="#bi-danh-archives" aria-label="Permalink to &quot;Bí Danh Archives&quot;">​</a></h1><p>Tên lệnh nén rút gọn.</p><p>Trang này giới thiệu một nhóm bí danh và các phím tắt lệnh thường dùng. Đọc trang này trước để hiểu quy ước đặt tên, đầu vào mong đợi và mẫu thực thi an toàn. Sau đó mở phụ lục tham khảo để xem toàn bộ danh sách lệnh và cú pháp chính xác. Các bí danh này giảm việc gõ lặp lại và duy trì hành vi quy trình làm việc nhất quán trên macOS, Linux và WSL.</p><h2 id="khi-nao-su-dung" tabindex="-1">Khi Nào Sử Dụng <a class="header-anchor" href="#khi-nao-su-dung" aria-label="Permalink to &quot;Khi Nào Sử Dụng&quot;">​</a></h2><p>Sử dụng trang này trước công việc shell hàng ngày khi bạn cần mẫu lệnh dự đoán được.</p><h2 id="bao-gom" tabindex="-1">Bao Gồm <a class="header-anchor" href="#bao-gom" aria-label="Permalink to &quot;Bao Gồm&quot;">​</a></h2><ul><li>Bí danh: 40</li><li>Hàm hỗ trợ: 3</li><li>Tệp nguồn: 1</li></ul><h2 id="vi-du-nhanh" tabindex="-1">Ví Dụ Nhanh <a class="header-anchor" href="#vi-du-nhanh" aria-label="Permalink to &quot;Ví Dụ Nhanh&quot;">​</a></h2><ul><li><code>ac</code> → <code>&#39;compress&#39; # Nén chung (Archive Create)</code></li><li><code>acl</code> → <code>&#39;compress_large&#39; # Nén lớn kiểu cũ</code></li><li><code>bak</code> → <code>&#39;backup&#39; # Hàm sao lưu nhanh</code></li><li><code>c7z</code> → <code>&#39;7z a&#39; # Tạo kho 7z</code></li><li><code>cbz</code> → <code>&#39;bzip2 -zk&#39; # Nén bằng bzip2</code></li><li><code>cgz</code> → <code>&#39;gzip -cv&#39; # Nén bằng gzip</code></li><li><code>clz4</code> → <code>&#39;lz4 -zc&#39; # Nén bằng lz4</code></li><li><code>crar</code> → <code>&#39;rar a&#39; # Tạo kho rar</code></li><li><code>ctar</code> → <code>&#39;tar -cvf&#39; # Tạo kho tar</code></li><li><code>ctbz</code> → <code>&#39;tar -jcvf&#39; # Tạo kho tar.bz2</code></li><li><code>ctgz</code> → <code>&#39;tar -zcvf&#39; # Tạo kho tar.gz</code></li><li><code>ctxz</code> → <code>&#39;tar -Jcvf&#39; # Tạo kho tar.xz</code></li></ul><h2 id="buoc-tiep-theo" tabindex="-1">Bước Tiếp Theo <a class="header-anchor" href="#buoc-tiep-theo" aria-label="Permalink to &quot;Bước Tiếp Theo&quot;">​</a></h2><p>Mở danh sách đầy đủ:</p>',11)])])}const g=a(n,[["render",t]]);export{p as __pageData,g as default};
